def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if not unvisited_customers:
        return None

    def path_score(truck_pos, customer):
        distance_to_customer = np.linalg.norm(truck_pos - customer)
        potential_routes = [np.linalg.norm(depot_pos - customer) + distance_to_customer]
        for other_truck in all_truck_pos:
            if not np.array_equal(other_truck, truck_pos):
                potential_routes.append(np.linalg.norm(other_truck - customer))
        return distance_to_customer + np.std(potential_routes)

    best_score = float('inf')
    best_node = None

    for i, customer in enumerate(unvisited_customers):
        score = path_score(cur_truck_pos, customer)
        if score < best_score:
            best_score = score
            best_node = i

    if best_score == float('inf'):
        return None

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    min_cost = float('inf')
    best_node = None

    for i, customer in enumerate(unvisited_customers):
        total_cost = 0

        # Calculate the cost if this customer is the next choice for the truck
        total_cost += distance(cur_truck_pos, customer)

        remaining_customers = unvisited_customers[:i] + unvisited_customers[i+1:]

        # Add costs for remaining customers from the perspective of the other trucks
        for j, truck in enumerate(all_truck_pos):
            if not np.array_equal(truck, cur_truck_pos):
                # Calculate cost from other trucks; assume they'd go directly back to depot
                truck_cost = distance(truck, depot_pos)
                if remaining_customers:
                    closest_customer_dist = min(distance(truck, rem_customer) for rem_customer in remaining_customers)
                    truck_cost += closest_customer_dist
                total_cost += truck_cost

        if total_cost < min_cost:
            min_cost = total_cost
            best_node = i

    # Decide to wait if no significant cost benefit is identified
    if best_node is not None:
        return best_node
    else:
        return None

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    num_customers = len(unvisited_customers)

    if num_customers == 0:
        return 'None'

    def distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    cur_distances = [distance(cur_truck_pos, customer) for customer in unvisited_customers]

    if num_customers == 1:
        return 0

    # Evaluate the potential waiting cost at the unvisited customers
    min_distance_indices = np.argsort(cur_distances)
    best_node = min_distance_indices[0]
    cur_best_distance = cur_distances[best_node]

    for idx in min_distance_indices:
        if cur_distances[idx] <= cur_best_distance:
            best_node = idx
            break

    return best_node
